return [
  {
    json: {
      client: "Acme Retail",
      google_search_console_data_source_id: 4907543,
      metrics: {
        impressions: "GoogleSearchConsole@impressions",
        position: "GoogleSearchConsole@position"
      }
    }
  },
  {
    json: {
      client: "BlueWave Agency",
      google_search_console_data_source_id: 4907544,
      metrics: {
        impressions: "GoogleSearchConsole@impressions",
        position: "GoogleSearchConsole@position"
      }
    }
  },
  {
    json: {
      client: "Nexus Health",
      google_search_console_data_source_id: 4907545,
      metrics: {
        impressions: "GoogleSearchConsole@impressions",
        position: "GoogleSearchConsole@position"
      }
    }
  }
];

// 1. Extract the two datasets from the merged content
// impressions are in index 0, positions are in index 1
const impressionsList = $json.content[0][0].text.results[0].data_points;
const positionsList = $json.content[1][0].text.results[0].data_points;

const urlMap = {};

// 2. Map Impressions by URL
impressionsList.forEach(item => {
  const url = item.dimension_values[0].value;
  urlMap[url] = {
    url: url,
    impressions: item.value,
    avgPosition: null
  };
});

// 3. Join Positions to the Map
positionsList.forEach(item => {
  const url = item.dimension_values[0].value;
  const position = parseFloat(item.value.toFixed(2));

  if (urlMap[url]) {
    urlMap[url].avgPosition = position;
  } else {
    // URL exists in position data but not impressions (rare but possible)
    urlMap[url] = {
      url: url,
      impressions: 0,
      avgPosition: position
    };
  }
});

// 4. Convert to array and sort by importance (high impressions)
const combinedResults = Object.values(urlMap)
  .filter(page => page.impressions > 5) // Filter out low-traffic noise
  .sort((a, b) => b.impressions - a.impressions);

return {
  total_pages_analyzed: combinedResults.length,
  seo_summary: combinedResults
};
